#include <string>
#include <algorithm>

using namespace std;

bool isBinaryPalindrome(long long k) {
    if (k == 0) return true;
    string binary;
    while (k > 0) {
        binary += (k % 2) ? '1' : '0';
        k /= 2;
    }
    string rev = binary;
    reverse(rev.begin(), rev.end());
    return binary == rev;
}

long long solve(long long n) {
    long long count = 0;
    for (long long k = 0; k <= n; ++k) {
        if (isBinaryPalindrome(k)) {
            ++count;
        }
    }
    return count;
}
